/**
 * Recebe items contendo campos Redis1 e Redis2 como strings JSON de arrays de mensagens.
 * Analisa ambos, une apenas as mensagens diferentes (sem duplicatas) e retorna uma única string.
 */
function mergeUniqueMessages(items) {
  // Obtém as strings brutas
  const raw1 = items[0].json.Redis1;
  const raw2 = items[0].json.Redis2;

  // Função para parsear com segurança
  function safeParse(raw) {
    if (!raw) return [];
    try {
      const parsed = JSON.parse(raw);
      return Array.isArray(parsed) ? parsed : [parsed];
    } catch {
      return [raw];
    }
  }

  // Parse das duas fontes
  const arr1 = safeParse(raw1);
  const arr2 = safeParse(raw2);

  // Une e remove duplicatas mantendo ordem de ocorrência
  const unique = [];
  [...arr1, ...arr2].forEach(msg => {
    if (!unique.includes(msg)) unique.push(msg);
  });

  // Junta numa única conversa
  const conversation = unique.join(' ');

  return [{ json: { conversation } }];
}

// No n8n Function Node, basta retornar:
